qry:select.qry:xquery:
for $r in sql(' select PER02.OI_PERSONAL_EMP, PER02.E_NUMERO_LEGAJO, PER01.D_APE_Y_NOM, ORG03.c_empresa, ORG03.d_empresa, PER02.oi_tipo_personal, PER02.oi_categoria_ult from
PER02_PERSONAL_EMP AS PER02, org03_empresas AS ORG03, PER01_PERSONAL AS PER01, liq19_liquidacion AS LIQ19, liq07_personal AS LIQ07, LIQ01_TLIQ_TPER as L01 JOIN
PER02.oi_empresa INNER org03.oi_empresa, liq19.oi_empresa INNER org03.oi_empresa, liq07.oi_personal_emp INNER per02.oi_personal_emp, PER02.OI_PERSONAL INNER PER01.OI_PERSONAL, L01.oi_tipo_personal INNER per02.oi_tipo_personal, L01.oi_tipo_liq INNER LIQ19.oi_tipo_liq WHERE PER02.OI_PERSONAL_EMP not in (SELECT liq25.oi_personal_emp FROM liq25_personal_liq AS LIQ25 WHERE liq25.oi_liquidacion = {%= #FILTRO:@oi_liquidacion %}) AND liq19.OI_LIQUIDACION = {%= #FILTRO:@oi_liquidacion %} and NOT(LIQ19.oi_tipo_liq = 1) and per02.oi_indic_activo = 1 {%? (#FILTRO:@todos=1) {% and liq07.oi_personal_emp not in (select liq25.oi_personal_emp from liq25_personal_liq as liq25 where liq25.oi_liquidacion = {%= #FILTRO:@oi_Liquidacion %}) %}
{% {%? (#FILTRO:@oi_tipo!='') {% and PER02.oi_tipo_personal {%? (#FILTRO:@excluir=1) {% != %} {% = %} %} {%= #FILTRO:@oi_tipo %} %} {% %} %} {%? (#FILTRO:@oi_categoria!='') {% and PER02.oi_categoria_ult {%? (#FILTRO:@excluir=1) {% != %} {% = %} %} {%= #FILTRO:@oi_categoria %} %} {% %} %} {%? (#FILTRO:@oi_convenio!='') {% and PER02.oi_categoria_ult {%? (#FILTRO:@excluir=1) {% not in %} {% in %} %} (Select c.oi_categoria from ORG18_CATEGORIAS as c where c.oi_convenio = {%= #FILTRO:@oi_convenio%}) %} {% %} %}
{%? (string(#FILTRO:PERSONAS/PERSONA/@id)!='') {% and liq07.oi_personal_emp {%? (#FILTRO:@excluir=1) {% not in %} {% in %} %} ({%=string(#FILTRO:PERSONAS/PERSONA/@id) %}) and liq07.oi_personal_emp not in (select liq25.oi_personal_emp from liq25_personal_liq as liq25 where liq25.oi_liquidacion = {%= #FILTRO:@oi_Liquidacion %}) %} {% %} %} %} %} order by E_NUMERO_LEGAJO ASC
')/ROWS/ROW
